from html.parser import HTMLParser
import sys

class TextExtractor(HTMLParser):
    def __init__(self):
        super().__init__()
        self.text = []
        self.skip = False
    def handle_starttag(self, tag, attrs):
        if tag in ('script','style'):
            self.skip = True
    def handle_endtag(self, tag):
        if tag in ('script','style'):
            self.skip = False
    def handle_data(self, data):
        if not self.skip:
            t = data.strip()
            if t:
                self.text.append(t)

with open('/home/mega/Downloads/monad.html','r',errors='ignore') as f:
