#!/usr/bin/env python3
"""
OmegA Master Evaluation Harness
Iterates through all registered architectural specifications and validates them.
"""
import subprocess
import json
from pathlib import Path

# Mapping of SPEC_IDs to Validation Script/Harness Paths
VALIDATION_MAP = {
    "AEGIS_IDENTITY_ENFORCEMENT": "evals/test_aegis_identity.py",
    # ... additional harnesses can be mapped here as they are developed
}

def run_suite():
    print("Running Master OmegA Evaluation Suite...")
    results = {}

    # Get all specs
    auditor_output = subprocess.check_output(["python3", "tools/spec_auditor.py"]).decode()

    for spec_id in VALIDATION_MAP:
        harness = Path(VALIDATION_MAP[spec_id])
        if harness.exists():
            print(f"Validating [{spec_id}]...")
            try:
                subprocess.check_call(["python3", str(harness)])
                results[spec_id] = "PASS"
            except subprocess.CalledProcessError:
                results[spec_id] = "FAIL"
        else:
            results[spec_id] = "NO_HARNESS_FOUND"

    # Generate Summary Report
    with open("evals/final_evaluation_report.json", "w") as f:
        json.dump(results, f, indent=2)

    print("\n--- Master Evaluation Summary ---")
    for sid, status in results.items():
        print(f"{sid}: {status}")
    print("\nReport saved to: evals/final_evaluation_report.json")

if __name__ == "__main__":
    Path("evals").mkdir(exist_ok=True)
    run_suite()

#!/usr/bin/env python3
"""
Eval Forge: AEGIS Identity Enforcement Validator
Validates the AEGIS_IDENTITY_ENFORCEMENT spec.
"""

def test_aegis_identity_enforcement():
    print("Test AEGIS_IDENTITY_ENFORCEMENT: Enforce identity before execution")

    # Mocking the RunEnvelope without Identity Kernel
    run_envelope = {
        "identity_kernel": None, # Missing identity
        "governance_policy": "STRICT",
        "action": "execute_shell_command"
    }

    def aegis_risk_gate(envelope):
        if envelope["identity_kernel"] is None:
            return "BLOCKED: Missing Identity"
        return "ALLOWED"

    result = aegis_risk_gate(run_envelope)

    if "BLOCKED" in result:
        print(f"Validation PASSED: {result}")
        return True
    else:
        print(f"Validation FAILED: {result}")
        return False

if __name__ == "__main__":
    if test_aegis_identity_enforcement():
        exit(0)
    else:
        exit(1)

#!/usr/bin/env python3
import os
import re
import argparse
import sys
from pathlib import Path
from urllib.parse import unquote

LINK_PATTERN = re.compile(r'\[([^\]]+)\]\(([^)]+)\)')
SPEC_PATTERN = re.compile(r'@OMEGA_SPEC:\s*([A-Z0-9_]+)\s*\|\s*(.*)')

def scan_files(root_path):
    specs = {}
    broken_links = []

    # Debug print to stderr to ensure it appears
    print(f"DEBUG: Scanning in {root_path}...", file=sys.stderr)

    for root, dirs, files in os.walk(root_path):
        if ".git" in dirs:
            dirs.remove(".git")

        for file in files:
            path = Path(root) / file
            try:
                content = path.read_text(encoding="utf-8", errors="ignore")
                for match in SPEC_PATTERN.finditer(content):
                    spec_id, desc = match.groups()
                    if spec_id not in specs:
                        specs[spec_id] = {"desc": desc, "locations": []}
                    specs[spec_id]["locations"].append(str(path))
                if file.endswith(".md"):
                    for match in LINK_PATTERN.finditer(content):
                        _, link = match.groups()
                        if not link.startswith(("http", "mailto:")):
                            if "#" in link: link = link.split("#")[0]
                            if link and not (path.parent / unquote(link)).resolve().exists():
                                broken_links.append(f"{path}: Broken link to '{link}'")
            except Exception:
                continue
    return specs, broken_links

if __name__ == "__main__":
    parser = argparse.ArgumentParser()
    parser.add_argument("--root", default=".")
    args = parser.parse_args()
    root = Path(args.root).resolve()
    specs, broken_links = scan_files(root)
    print(f"\n--- Audit Results ---")
    print(f"Specs Identified: {len(specs)}")
    for sid, info in specs.items():
        print(f"  [{sid}] {info['desc']} (Found in {len(info['locations'])} file(s))")
    if broken_links:
        for e in broken_links: print(f"  - {e}")

